from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subjects = set()
    predicates = {}
    for triple in triples:
        subjects.add(triple.subject)
        if triple.subject not in predicates:
            predicates[triple.subject] = []
        predicates[triple.subject].append((triple.predicate, triple.object))

    sentence = ""
    subject = triples[0].subject
    if subject in predicates:
        sentence += f"{subject} "
        for i, (predicate, object) in enumerate(predicates[subject]):
            if predicate == "cityServed":
                sentence += f"serves the city of {object}, "
            elif predicate == "location":
                sentence += f"located in {object}, "
            elif predicate == "operatingOrganisation":
                sentence += f"operated by {object}, "
            elif predicate == "elevationAboveTheSeaLevel":
                sentence += f"with an elevation of {object} meters, "
            elif predicate == "runwayLength":
                sentence += f"with a runway length of {object} meters, "
            elif predicate == "runwayName":
                sentence += f"with a runway named {object}, "
            elif predicate == "country":
                sentence += f"in the country of {object}, "
            elif predicate == "isPartOf":
                sentence += f"part of {object}, "
        sentence = sentence.strip()[:-1] + "."
    return sentence

